document.addEventListener("DOMContentLoaded",(function(){const t={eponymo:{selector:".sync-eponymo",maxLength:25},onoma:{selector:".sync-onoma",maxLength:15},afm_ergazomenoy:{selector:".sync-afm",maxLength:null},amka_ergazomenoy:{selector:".sync-amka",maxLength:null}};function truncateText(t,e){return!e||t.length<=e?t:t.substring(0,e)+"..."}Object.keys(t).forEach((e=>{const n=document.getElementById(e);if(!n)return;const o=t[e];n.addEventListener("input",(function(){const t=truncateText(this.value,o.maxLength);document.querySelectorAll(o.selector).forEach((e=>{e.textContent=t,o.maxLength&&this.value.length>o.maxLength?e.setAttribute("title",this.value):e.removeAttribute("title")}))}));const a=truncateText(n.value,o.maxLength);document.querySelectorAll(o.selector).forEach((t=>{t.textContent=a,o.maxLength&&n.value.length>o.maxLength&&t.setAttribute("title",n.value)}))}))}));